};

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function getTacticalBriefing(score: number, weapon: string) {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `You are a tactical AI in a voxel warfare game. The player currently has a score of ${score} and is using the ${weapon}. Give a short (max 2 sentences) gritty tactical briefing or encouragement.`,
      config: {
        temperature: 0.7,
      }
    });
    return response.text || "Eyes sharp, soldier. The blocks aren't going to break themselves.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Tactical comms down. Stay alert.";
  }
}

import { useState, useCallback } from 'react';
import { nanoid } from 'nanoid';
import { Block, BlockType, WeaponType } from '../types';
import { WEAPONS } from '../constants';

const INITIAL_BLOCKS: Block[] = [
  { id: nanoid(), pos: [0, 0, -5], type: 'target' },
  { id: nanoid(), pos: [2, 1, -8], type: 'target' },
  { id: nanoid(), pos: [-2, 2, -10], type: 'target' },
  { id: nanoid(), pos: [5, 0, -12], type: 'target' },
  { id: nanoid(), pos: [-4, 0, -6], type: 'target' },
];

export const useStore = () => {
  const [blocks, setBlocks] = useState<Block[]>(INITIAL_BLOCKS);
  const [score, setScore] = useState(0);
  const [currentWeapon, setCurrentWeapon] = useState<WeaponType>('pistol');
  const [ammo, setAmmo] = useState<Record<WeaponType, number>>({
    pistol: WEAPONS.pistol.maxAmmo,
    rifle: WEAPONS.rifle.maxAmmo,
    sniper: WEAPONS.sniper.maxAmmo,
  });

  const addBlock = useCallback((x: number, y: number, z: number, type: BlockType = 'grass') => {
    setBlocks(prev => [...prev, { id: nanoid(), pos: [x, y, z], type }]);
  }, []);

  const removeBlock = useCallback((id: string) => {
    setBlocks(prev => {
        const block = prev.find(b => b.id === id);
        if (block?.type === 'target') setScore(s => s + 100);
        return prev.filter(b => b.id !== id);
    });
  }, []);

  const fireWeapon = useCallback(() => {
    setAmmo(prev => {
        if (prev[currentWeapon] <= 0) return prev;
        return { ...prev, [currentWeapon]: prev[currentWeapon] - 1 };
    });
  }, [currentWeapon]);

  const reloadWeapon = useCallback(() => {
    setAmmo(prev => ({ ...prev, [currentWeapon]: WEAPONS[currentWeapon].maxAmmo }));
  }, [currentWeapon]);

  const switchWeapon = useCallback((type: WeaponType) => {
    setCurrentWeapon(type);
  }, []);

  const resetBlocks = useCallback(() => {
    setBlocks(INITIAL_BLOCKS);
    setScore(0);
  }, []);

  return {
    blocks,
    addBlock,
    removeBlock,
    score,
    currentWeapon,
    ammo,
    fireWeapon,
    reloadWeapon,
    switchWeapon,
    resetBlocks,
  };
};

import React, { useState } from 'react';
import { ThreeEvent } from '@react-three/fiber';
import { BLOCK_COLORS } from '../constants';
import { BlockType } from '../types';

interface CubeProps {
  position: [number, number, number];
  type: BlockType;
  id: string;
  removeBlock: (id: string) => void;
  addBlock: (x: number, y: number, z: number) => void;
}

const Cube: React.FC<CubeProps> = ({ position, type, id, removeBlock, addBlock }) => {
  const [hovered, setHovered] = useState(false);

  const handleClick = (e: ThreeEvent<MouseEvent>) => {
    e.stopPropagation();
    const { x, y, z } = e.point;
    const clickedFace = Math.floor(e.faceIndex! / 2);

    if (e.button === 0) { // Left click: Break or Shoot
       // Handled via Raycaster in Player for shooting
    } else if (e.button === 2) { // Right click: Build
      const [px, py, pz] = position;
      if (clickedFace === 0) addBlock(px + 1, py, pz);
      else if (clickedFace === 1) addBlock(px - 1, py, pz);
      else if (clickedFace === 2) addBlock(px, py + 1, pz);
      else if (clickedFace === 3) addBlock(px, py - 1, pz);
      else if (clickedFace === 4) addBlock(px, py, pz + 1);
      else if (clickedFace === 5) addBlock(px, py, pz - 1);
    }
  };

  return (
    <mesh
      position={position}
      onPointerOver={() => setHovered(true)}
      onPointerOut={() => setHovered(false)}
      onPointerDown={handleClick}
    >
      <boxGeometry args={[1, 1, 1]} />
      <meshStandardMaterial
        color={hovered ? '#fff' : BLOCK_COLORS[type] || '#fff'}
        transparent={type === 'glass'}
        opacity={type === 'glass' ? 0.6 : 1.0}
        map={null} // Simplified for demo
      />
    </mesh>
  );
};

export default Cube;

